"""
Idempotent inserter for the 200 test users generated by generate_test_users.py.

What it does:
  1. Uploads 2 shared placeholder photos (embedded below as base64, so this
     file is self-contained) to your MinIO `photos-public` bucket, if they
     aren't there already.
  2. Reads test_users_200.json.
  3. Skips any email that already exists in the DB (safe to re-run).
  4. Inserts: users, user_profiles, user_settings, photos (3/user),
     user_interests (8 random interests/user, picked from whatever's
     already in your `interests` table).

Run from your backend/ directory (same place you'd run other app.db
scripts), with your venv active and .env loaded:

    python -m app.db.scripts.seed_test_users_200

(or: place this file anywhere and run `python seed_test_users_200.py`,
as long as `app` is importable — i.e. run it from backend/.)

Requires: boto3 (for MinIO upload). Install with:
    pip install boto3 --break-system-packages
"""
import asyncio
import base64
import json
import random
import sys
import uuid
from datetime import date
from pathlib import Path

from sqlalchemy import select, text
from sqlalchemy.ext.asyncio import AsyncSession, async_sessionmaker, create_async_engine

from app.core.config import settings
from app.models.user import User
from app.models.user_profile import UserProfile
from app.models.user_settings import UserSettings
from app.models.photo import Photo
from app.models.user_interest import UserInterest

try:
    from app.core.security import get_password_hash
except ImportError:
    # Fallback if your project uses a different name/location for this.
    from passlib.context import CryptContext
    _pwd_context = CryptContext(schemes=["bcrypt"], deprecated="auto")

    def get_password_hash(password: str) -> str:
        return _pwd_context.hash(password)

JSON_PATH = Path(__file__).parent / "test_users_200.json"
if not JSON_PATH.exists():
    # fall back to seed_data/ convention used by dummy_users.json
    JSON_PATH = Path(__file__).parent.parent / "seed_data" / "test_users_200.json"

PASSWORD = "12345678"


# --- Embedded placeholder photos (~9KB each), so this script needs no other files ---
MALE_PHOTO_B64 = ""
FEMALE_PHOTO_B64 = ""


def upload_placeholder_photos():
    """Uploads the 2 shared placeholder images to the MinIO public bucket
    (idempotent — skips if the object already exists)."""
    try:
        import boto3
        from botocore.client import Config as BotoConfig
        from botocore.exceptions import ClientError
    except ImportError:
        print("boto3 not installed — skipping photo upload. "
              "Install with: pip install boto3 --break-system-packages")
        print("(User/profile/interest rows will still be inserted; "
              "photo rows will point at keys that don't exist yet in MinIO "
              "until you upload them separately.)")
        return

    s3 = boto3.client(
        "s3",
        endpoint_url=settings.S3_ENDPOINT_URL,
        aws_access_key_id=settings.S3_ACCESS_KEY,
        aws_secret_access_key=settings.S3_SECRET_KEY,
        region_name=getattr(settings, "S3_REGION", "us-east-1"),
        config=BotoConfig(signature_version="s3v4"),
    )
    bucket = settings.S3_PUBLIC_BUCKET

    for key, b64_data in (
        ("seed/male_placeholder.jpg", MALE_PHOTO_B64),
        ("seed/female_placeholder.jpg", FEMALE_PHOTO_B64),
    ):
        try:
            s3.head_object(Bucket=bucket, Key=key)
            print(f"  {key} already exists in {bucket}, skipping upload")
            continue
        except ClientError:
            pass  # doesn't exist yet, upload it

        s3.put_object(
            Bucket=bucket,
            Key=key,
            Body=base64.b64decode(b64_data),
            ContentType="image/jpeg",
        )
        print(f"  uploaded {key} -> {bucket}")


async def main():
    if not JSON_PATH.exists():
        sys.exit(f"Could not find test_users_200.json (looked in {JSON_PATH}). "
                  f"Run generate_test_users.py first and place the output "
                  f"next to this script or in app/db/seed_data/.")

    data = json.loads(JSON_PATH.read_text(encoding="utf-8"))

    print("Uploading placeholder photos to MinIO...")
    upload_placeholder_photos()

    engine = create_async_engine(settings.DATABASE_URL)
    async_session = async_sessionmaker(engine, expire_on_commit=False)

    async with async_session() as session:
        # 1. Find which of these emails already exist -> idempotent re-runs
        emails = [u["email"] for u in data["users"]]
        result = await session.execute(select(User.email).where(User.email.in_(emails)))
        existing_emails = {row[0] for row in result.all()}
        new_users = [u for u in data["users"] if u["email"] not in existing_emails]

        if not new_users:
            print(f"All {len(emails)} test users already exist. Nothing to insert.")
            return

        print(f"Inserting {len(new_users)} new users "
              f"({len(existing_emails)} already existed, skipped)...")

        # 2. Fetch available interest IDs from the DB (already seeded by
        #    seed_interests.py). We assign 8 random ones per user.
        result = await session.execute(text("SELECT id FROM interests"))
        interest_ids = [row[0] for row in result.all()]
        if len(interest_ids) < 8:
            print(f"WARNING: only {len(interest_ids)} interests found in DB "
                  f"— run seed_interests.py first for a full set of 158. "
                  f"Proceeding with what's available.")

        # 3. Hash the shared password once — same for all 200 users.
        password_hash = get_password_hash(PASSWORD)

        new_user_ids = {u["email"] for u in new_users}
        profiles_by_email = {p["user_id"]: p for p in data["profiles"]}
        settings_by_uid = {s["user_id"]: s for s in data["settings"]}
        photos_by_uid = {}
        for photo in data["photos"]:
            photos_by_uid.setdefault(photo["user_id"], []).append(photo)

        for u in new_users:
            uid_str = u["id"]
            uid = uuid.UUID(uid_str)
            user = User(
                id=uid,
                email=u["email"],
                password_hash=password_hash,
                is_active=u["is_active"],
                phone_verified=u["phone_verified"],
                registration_status=u["registration_status"],
                referral_code=u["referral_code"],
                referred_by=u["referred_by"],
            )
            session.add(user)

            p = profiles_by_email[uid_str]
            session.add(UserProfile(
                user_id=uid,
                name=p["name"],
                birth_date=date.fromisoformat(p["birth_date"]),
                gender=p["gender"],
                sexual_orientation=p["sexual_orientation"],
                bio=p["bio"],
                height=p["height"],
                weight=p["weight"],
                body_type=p["body_type"],
                relationship_status=p["relationship_status"],
                living_situation=p["living_situation"],
                children_status=p["children_status"],
                smoking=p["smoking"],
                drinking=p["drinking"],
                languages=p["languages"],
                education=p["education"],
                workplace=p["workplace"],
                religion=p["religion"],
                ethnicity=p["ethnicity"],
                political_orientation=p["political_orientation"],
                lat=p["lat"],
                lng=p["lng"],
                country=p["country"],
                province=p["province"],
                city=p["city"],
                location_manual=p["location_manual"],
                is_verified=p["is_verified"],
                premium_until=p["premium_until"],
            ))

            s = settings_by_uid[uid_str]
            session.add(UserSettings(
                user_id=uid,
                hide_last_seen=s["hide_last_seen"],
                hide_online_status=s["hide_online_status"],
                push_enabled=s["push_enabled"],
                like_notifications=s["like_notifications"],
                match_notifications=s["match_notifications"],
                message_notifications=s["message_notifications"],
                language=s["language"],
                dark_mode=s["dark_mode"],
            ))

            for photo in photos_by_uid.get(uid_str, []):
                session.add(Photo(
                    user_id=uid,
                    url=photo["url"],
                    order=photo["order"],
                    is_main=photo["is_main"],
                    status=photo["status"],
                    reject_reason=photo["reject_reason"],
                    face_verified=photo["face_verified"],
                ))

            if interest_ids:
                k = min(8, len(interest_ids))
                for interest_id in random.sample(interest_ids, k):
                    session.add(UserInterest(user_id=uid, interest_id=interest_id))

        await session.commit()
        print(f"Done. Inserted {len(new_users)} users "
              f"(login with any test{{N}}@test.com / password: {PASSWORD}).")

    await engine.dispose()


if __name__ == "__main__":
    asyncio.run(main())